# ⚠️ TOKENNI O'ZGARTIR !!!
BOT_TOKEN = "8663649354:AAGDw8eBwEVb5ck7yEbb4hX6Ya3cCZAUxMY"

import telebot
from telebot import types
from datetime import datetime
import json, os, time

ADMIN_ID = 7642574758

PRODUCTS = [
    {"name": "🥪 Sendwich", "price": 10000},
    {"name": "🧒 Detskiy sendwich", "price": 5000},
    {"name": "🍗 Tovuqli sendwich", "price": 12000},
    {"name": "🍔 Burger", "price": 15000},
]

bot = telebot.TeleBot(BOT_TOKEN)
DATA_FILE = "bot_data.json"
sessions = {}

# ---------------- DB ----------------
def load():
    if os.path.exists(DATA_FILE):
        with open(DATA_FILE, encoding="utf-8") as f:
            return json.load(f)
    return {"users": {}, "reports": []}

def save(data):
    with open(DATA_FILE, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

def now():
    return datetime.now().strftime("%Y-%m-%d %H:%M")

def today():
    return datetime.now().strftime("%Y-%m-%d")

def fmt(n):
    return f"{n:,}".replace(",", " ")

# ---------------- START ----------------
@bot.message_handler(commands=["start"])
def start(msg):
    bot.send_message(msg.chat.id, "🛒 Savdoni boshlashni bosing",
                     reply_markup=types.ReplyKeyboardMarkup(resize_keyboard=True).add("🛒 Savdoni boshlash"))

# ---------------- START SALE ----------------
@bot.message_handler(func=lambda m: m.text == "🛒 Savdoni boshlash")
def sale_start(msg):
    uid = msg.from_user.id
    sessions[uid] = {"step": "products", "report": {"products": {}, "vozvrat": {}}}

    bot.send_message(uid, "📦 Mahsulot tanlang:",
                     reply_markup=products_kb({}))

# ---------------- KEYBOARDS ----------------
def products_kb(counts):
    kb = types.ReplyKeyboardMarkup(resize_keyboard=True)
    for i, p in enumerate(PRODUCTS):
        c = counts.get(str(i), 0)
        kb.add(f"{p['name']} [{c} ta]" if c else p['name'])
    kb.add("✅ Tayyor", "🔙 Orqaga")
    return kb

def numpad():
    kb = types.ReplyKeyboardMarkup(resize_keyboard=True)
    kb.row("1","2","3")
    kb.row("4","5","6")
    kb.row("7","8","9")
    kb.row("🔙","0","✅")
    return kb

# ---------------- SELECT PRODUCT ----------------
@bot.message_handler(func=lambda m: sessions.get(m.from_user.id, {}).get("step") == "products")
def select_product(msg):
    uid = msg.from_user.id
    text = msg.text
    sess = sessions[uid]

    if text == "✅ Tayyor":
        sess["step"] = "vozvrat"
        bot.send_message(uid, "🔄 Vozvrat kiriting:",
                         reply_markup=products_kb({}))
        return

    for i,p in enumerate(PRODUCTS):
        if p["name"] in text:
            sess["selected"] = i
            sess["qty"] = ""
            sess["step"] = "qty"

            m = bot.send_message(uid,
                f"{p['name']}\nSoni: 0",
                reply_markup=numpad())
            sess["msg_id"] = m.message_id
            return

# ---------------- QTY INPUT (FIXED) ----------------
@bot.message_handler(func=lambda m: sessions.get(m.from_user.id, {}).get("step") == "qty")
def qty_input(msg):
    uid = msg.from_user.id
    sess = sessions[uid]
    text = msg.text

    if text.isdigit():
        sess["qty"] += text

    elif text == "🔙":
        sess["qty"] = sess["qty"][:-1]

    elif text == "✅":
        q = int(sess["qty"] or "0")
        idx = sess["selected"]
        sess["report"]["products"][str(idx)] = q
        sess["step"] = "products"

        bot.send_message(uid, "✅ Saqlandi",
                         reply_markup=products_kb(sess["report"]["products"]))
        return

    q = int(sess["qty"] or "0")
    p = PRODUCTS[sess["selected"]]

    bot.edit_message_text(
        f"{p['name']}\nSoni: {q}\nJami: {fmt(q*p['price'])}",
        uid,
        sess["msg_id"],
        reply_markup=numpad()
    )

# ---------------- VOZVRAT ----------------
@bot.message_handler(func=lambda m: sessions.get(m.from_user.id, {}).get("step") == "vozvrat")
def vozvrat(msg):
    uid = msg.from_user.id
    sess = sessions[uid]

    if msg.text == "✅ Tayyor":
        finish(uid)
        return

    for i,p in enumerate(PRODUCTS):
        if p["name"] in msg.text:
            sess["selected"] = i
            sess["qty"] = ""
            sess["step"] = "qty_v"

            m = bot.send_message(uid,
                f"🔄 {p['name']}\nSoni: 0",
                reply_markup=numpad())
            sess["msg_id"] = m.message_id
            return

# ---------------- VOZVRAT QTY ----------------
@bot.message_handler(func=lambda m: sessions.get(m.from_user.id, {}).get("step") == "qty_v")
def qty_v(msg):
    uid = msg.from_user.id
    sess = sessions[uid]
    text = msg.text

    if text.isdigit():
        sess["qty"] += text
    elif text == "🔙":
        sess["qty"] = sess["qty"][:-1]
    elif text == "✅":
        q = int(sess["qty"] or "0")
        idx = sess["selected"]
        sess["report"]["vozvrat"][str(idx)] = q
        sess["step"] = "vozvrat"

        bot.send_message(uid, "✅ Vozvrat saqlandi",
                         reply_markup=products_kb(sess["report"]["vozvrat"]))
        return

    q = int(sess["qty"] or "0")
    p = PRODUCTS[sess["selected"]]

    bot.edit_message_text(
        f"🔄 {p['name']}\nSoni: {q}",
        uid,
        sess["msg_id"],
        reply_markup=numpad()
    )

# ---------------- FINISH ----------------
def finish(uid):
    sess = sessions[uid]
    r = sess["report"]

    total_sale = sum(PRODUCTS[int(i)]["price"] * q for i,q in r["products"].items())
    total_vozv = sum(PRODUCTS[int(i)]["price"] * q for i,q in r["vozvrat"].items())
    net = total_sale - total_vozv

    text = (
        f"📦 Sotuv: {fmt(total_sale)}\n"
        f"🔄 Vozvrat: -{fmt(total_vozv)}\n"
        f"━━━━━━━━━━━━\n"
        f"💰 Klient to'lovi: {fmt(net)}"
    )

    bot.send_message(uid, text)

    data = load()
    data["reports"].append({
        "date": today(),
        "sale": total_sale,
        "vozv": total_vozv,
        "net": net
    })
    save(data)

    sessions.pop(uid)

# ---------------- RUN ----------------
print("Bot ishga tushdi")
bot.infinity_polling()                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            